# DiskStation Monitor — TypeScript fix patch
# Run: Set-ExecutionPolicy Bypass -Scope Process -Force; .\PATCH.ps1

$RepoPath = "C:\Users\LionelMosley\Documents\HTML\Synology - DiskStation Monitor"
Set-Location $RepoPath
Write-Host "Applying TypeScript fixes..." -ForegroundColor Cyan

# backend/src/services/jwt.ts
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$fullPath = Join-Path $RepoPath "backend/src/services/jwt.ts"
[System.IO.File]::WriteAllBytes($fullPath, $bytes)
Write-Host "  wrote backend/src/services/jwt.ts" -ForegroundColor Green

# backend/src/workers/pollEngine.ts
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$fullPath = Join-Path $RepoPath "backend/src/workers/pollEngine.ts"
[System.IO.File]::WriteAllBytes($fullPath, $bytes)
Write-Host "  wrote backend/src/workers/pollEngine.ts" -ForegroundColor Green

git add backend/src/services/jwt.ts backend/src/workers/pollEngine.ts
git commit -m "fix: TypeScript type errors in jwt.ts and pollEngine.ts"
git push origin main

if ($LASTEXITCODE -eq 0) {
    Write-Host "`n✅ Patch pushed — Railway is rebuilding." -ForegroundColor Green
    Write-Host "   The build should succeed this time." -ForegroundColor Cyan
} else {
    Write-Host "`n❌ Push failed." -ForegroundColor Red
}